@Test
public void visibilityAttribute_publicVisibility_isRecorded() throws Exception {
  scratch.file(
      "pkg/BUILD",
      """
      load("//rules:my_rule.bzl", "my_rule")
      my_rule(
          name = "my_target",
          required_str = "hello",
          visibility = ["//visibility:public"],
      )
      """);
  Package pkg = loadPackage("pkg");

  assertNoEvents();
  assertThat(pkg.containsErrors()).isFalse();
  Rule rule = (Rule) pkg.getTarget("my_target");
  assertThat(rule).isNotNull();
  // Verify that visibility was set to //visibility:public.
  List<Label> visLabels = rule.getVisibilityDeclaredLabels();
  assertThat(visLabels)
      .containsExactly(Label.parseCanonical("//visibility:public"));
}

@Test
public void visibilityAttribute_privateVisibility_isRecorded() throws Exception {
  scratch.file(
      "pkg/BUILD",
      """
      load("//rules:my_rule.bzl", "my_rule")
      my_rule(
          name = "my_target",
          required_str = "hello",
          visibility = ["//visibility:private"],
      )
      """);
  Package pkg = loadPackage("pkg");

  assertNoEvents();
  assertThat(pkg.containsErrors()).isFalse();
  Rule rule = (Rule) pkg.getTarget("my_target");
  assertThat(rule).isNotNull();
  // //visibility:private is normalized to an empty label list.
  List<Label> visLabels = rule.getVisibilityDeclaredLabels();
  assertThat(visLabels).isEmpty();
}

