package com.google.devtools.build.lib.packages;

import static com.google.common.truth.Truth.assertThat;

import com.google.devtools.build.lib.cmdline.Label;
import com.google.devtools.build.lib.packages.util.PackageLoadingTestCase;
import java.util.List;
import org.junit.Before;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.junit.runners.JUnit4;

/**
 * Unit tests for Starlark evaluation of rule() calls in BUILD files. Covers rule instantiation,
 * attribute validation, and error handling.
 */
@RunWith(JUnit4.class)
public final class StarlarkRuleEvalTest extends PackageLoadingTestCase {

  // A simple rule .bzl file used by multiple tests. Created in setUp so each test can load it.
  @Before
  public void createRuleBzlFiles() throws Exception {
    // Rule with a mandatory string attribute and an optional string attribute with a default.
    scratch.file(
        "rules/my_rule.bzl",
        """
        def _impl(ctx):
          pass

        my_rule = rule(
          implementation = _impl,
          attrs = {
            "required_str": attr.string(mandatory = True),
            "optional_str": attr.string(default = "default_value"),
            "str_list":     attr.string_list(),
            "src_label":    attr.label(allow_single_file = True),
            "src_labels":   attr.label_list(allow_files = True),
          },
        )
        """);
    scratch.file("rules/BUILD");
  }

  // ---------------------------------------------------------------------------
  // Helper methods
  // ---------------------------------------------------------------------------

  private Package loadPackage(String pkgid) throws Exception {
    return getTarget("//" + pkgid + ":BUILD").getPackage();
  }

  private static AttributeMap attributes(Rule rule) {
    return RawAttributeMapper.of(rule);
  }

  // ---------------------------------------------------------------------------
  // Test: basic rule instantiation with required attributes
  // ---------------------------------------------------------------------------

  @Test
  public void basicRuleInstantiation_succeeds() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    assertThat(rule).isNotNull();
    assertThat(rule.getRuleClass()).isEqualTo("my_rule");
  }

  // ---------------------------------------------------------------------------
  // Test: missing required attribute produces an error
  // ---------------------------------------------------------------------------

  @Test
  public void missingRequiredAttribute_producesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(name = "my_target")
        """);
    Package pkg = loadPackage("pkg");

    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("required_str");
  }

  // ---------------------------------------------------------------------------
  // Test: default attribute values are applied when attribute is omitted
  // ---------------------------------------------------------------------------

  @Test
  public void defaultAttributeValue_isAppliedWhenOmitted() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    String optVal = attributes(rule).get("optional_str", Type.STRING);
    assertThat(optVal).isEqualTo("default_value");
  }

  // ---------------------------------------------------------------------------
  // Test: explicitly supplied attribute value overrides the default
  // ---------------------------------------------------------------------------

  @Test
  public void explicitAttributeValue_overridesDefault() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            optional_str = "custom",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    String optVal = attributes(rule).get("optional_str", Type.STRING);
    assertThat(optVal).isEqualTo("custom");
  }

  // ---------------------------------------------------------------------------
  // Test: passing a list where a string is expected produces an error
  // ---------------------------------------------------------------------------

  @Test
  public void wrongTypeForStringAttribute_producesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = ["not", "a", "string"],
        )
        """);
    Package pkg = loadPackage("pkg");

    assertThat(pkg.containsErrors()).isTrue();
    // The error message should mention the attribute or type mismatch.
    assertContainsEvent("required_str");
  }

  // ---------------------------------------------------------------------------
  // Test: string_list attribute accepts a list of strings
  // ---------------------------------------------------------------------------

  @Test
  public void stringListAttribute_acceptsListOfStrings() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            str_list = ["a", "b", "c"],
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    List<String> strList = attributes(rule).get("str_list", Type.STRING_LIST);
    assertThat(strList).containsExactly("a", "b", "c").inOrder();
  }

  // ---------------------------------------------------------------------------
  // Test: passing a string where a list is expected produces an error
  // ---------------------------------------------------------------------------

  @Test
  public void wrongTypeForListAttribute_producesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            str_list = "not_a_list",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("str_list");
  }

  // ---------------------------------------------------------------------------
  // Test: label attribute accepts a valid label string
  // ---------------------------------------------------------------------------

  @Test
  public void labelAttribute_acceptsValidLabel() throws Exception {
    scratch.file("pkg/a.txt", "");
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            src_label = "a.txt",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    Label srcLabel = attributes(rule).get("src_label", BuildType.LABEL);
    assertThat(srcLabel).isEqualTo(Label.parseCanonical("//pkg:a.txt"));
  }

  // ---------------------------------------------------------------------------
  // Test: label_list attribute accepts a list of valid labels
  // ---------------------------------------------------------------------------

  @Test
  public void labelListAttribute_acceptsValidLabels() throws Exception {
    scratch.file("pkg/a.txt", "");
    scratch.file("pkg/b.txt", "");
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            src_labels = ["a.txt", "b.txt"],
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    List<Label> srcLabels = attributes(rule).get("src_labels", BuildType.LABEL_LIST);
    assertThat(srcLabels)
        .containsExactly(
            Label.parseCanonical("//pkg:a.txt"),
            Label.parseCanonical("//pkg:b.txt"))
        .inOrder();
  }

  // ---------------------------------------------------------------------------
  // Test: visibility attribute is accepted and stored on the rule
  // ---------------------------------------------------------------------------

  @Test
  public void visibilityAttribute_publicVisibility_isRecorded() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            visibility = ["//visibility:public"],
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    assertThat(rule).isNotNull();
    // Verify that visibility was set (the rule carries a non-null visibility).
    assertThat(rule.getVisibility()).isNotNull();
  }

  @Test
  public void visibilityAttribute_privateVisibility_isRecorded() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "my_target",
            required_str = "hello",
            visibility = ["//visibility:private"],
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = (Rule) pkg.getTarget("my_target");
    assertThat(rule).isNotNull();
    assertThat(rule.getVisibility()).isNotNull();
  }

  // ---------------------------------------------------------------------------
  // Test: rule name validation — valid names succeed
  // ---------------------------------------------------------------------------

  @Test
  public void validRuleName_alphanumericWithUnderscores_succeeds() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "valid_rule_name_123",
            required_str = "hello",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    assertThat(pkg.getRule("valid_rule_name_123")).isNotNull();
  }

  @Test
  public void validRuleName_withDots_succeeds() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "rule.with.dots",
            required_str = "hello",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    assertThat(pkg.getRule("rule.with.dots")).isNotNull();
  }

  // ---------------------------------------------------------------------------
  // Test: rule name validation — invalid names produce errors
  // ---------------------------------------------------------------------------

  @Test
  public void invalidRuleName_withColon_producesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "bad:name",
            required_str = "hello",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("bad:name");
  }

  @Test
  public void invalidRuleName_withSlash_producesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "bad/name",
            required_str = "hello",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("bad/name");
  }

  // ---------------------------------------------------------------------------
  // Test: duplicate rule names produce an error
  // ---------------------------------------------------------------------------

  @Test
  public void duplicateRuleName_producesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "dup",
            required_str = "first",
        )
        my_rule(
            name = "dup",
            required_str = "second",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertThat(pkg.containsErrors()).isTrue();
    assertContainsEvent("dup");
  }

  // ---------------------------------------------------------------------------
  // Test: multiple rules in the same package each get the right attribute values
  // ---------------------------------------------------------------------------

  @Test
  public void multipleRules_eachHaveCorrectAttributes() throws Exception {
    scratch.file(
        "pkg/BUILD",
        """
        load("//rules:my_rule.bzl", "my_rule")
        my_rule(
            name = "rule_a",
            required_str = "value_a",
        )
        my_rule(
            name = "rule_b",
            required_str = "value_b",
            optional_str = "override_b",
        )
        """);
    Package pkg = loadPackage("pkg");

    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();

    Rule ruleA = (Rule) pkg.getTarget("rule_a");
